      /* <flatten type="Javascript"> */
function load$CheckingReport$(g) {
  g._$k = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$t = g._getColumnOrder('tag');
  g._$f = 'keys';
  g.add_commandEvent(on$GridReport$ExecuteCommand);
  g.add_onResponseComplete(on$GridReport$ResponseComplete);
  g._grid = createGrid($get('subReport'), g, 'SubReport', '');
  g._grid.add_onRender(on$subReport$Render);
}
function dispose$CheckingReport$(g) {
  g._$k = g._$i = g._$t = g._$f = null;
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridReport$ResponseComplete);} catch (ex) {}
  try {g._grid.remove_onRender(on$ShiftScheduleGrid$Render);} catch (ex) {}
}
function on$subReport$Render(sender, eventArgs) {
  var g = eventArgs.grid;
  if (g._rowCount == 1) {
    g._setActiveCell(g._getItem(1, 1));
    g.executeCommand({ commandName: 'Edit', commandArgument: '0' });
  }
}
function scatter$GridReport$(g) {
  fill$Grid(g, true);
/*
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
  }
*/
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm, id = g.get_id();
  var v = String.format('$find(\'{0}\')._focusWhenTabChanged();', id);
  switch (action) {
    case 'New':
      if ((g._authorize$New != '1') ?  $message.show($df.getResources(g._language, "Message.NotAccess"), v) : request$ARCreate(g, action));
      e.type.cancelEvent = true;
      break;
    case 'Edit':
      if ((g._authorize$Edit != '1') ?  $message.show($df.getResources(g._language, "Message.NotAccess"), v) : request$ARDrillDown(g, action));
      e.type.cancelEvent = true;
      break;
    case 'Delete':
      if ((g._authorize$Delete != '1') ?  $message.show($df.getResources(g._language, "Message.NotAccess"), v) : request$ARDrillDown(g, action));
      e.type.cancelEvent = true;
      break;
    case 'Allocate':
      if (isCheck$Grid(g))
        if ((g._authorize$New != '1') ?  $message.show($df.getResources(g._language, "Message.NotAccess"), v) : request$ARAllocation(g, action));
      break;
    default:
      break;
  }
}
function on$GridReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, id = g.get_id();
  var v = String.format('$find(\'{0}\')._focusWhenTabChanged();', id);
  switch (context) {
    case 'Allocate':
      if ((result[0].Value != '1') ?  $message.show($df.getResources(g._language, "Message.NotAccess"), v) : g.showForm('ARMultiAllocationCreate'));
      break;
    case 'Edit':
      if (result[0].Value == 0) {
         var m = (g._language == 'v' ? 'Số chứng từ <span class="Highlight">' + g._getItemValue(g._activeRow, g._getColumnOrder('so_ct')) + ' </span> chưa phân bổ cho hóa đơn nào.' : 'This voucher <span class="Highlight">' + g._getItemValue(g._activeRow, g._getColumnOrder('so_ct')) + ' </span> has not been allocated to any invoice.');
         $message.show(m, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      }
      else if (result[0].Value == 1) {
        var gd = g._grid, a = [], key = g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec'));
        var c = String.fromCharCode(253), extKey = key + c + g._allocationType;
        setValue$Array (a, ['stt_rec', 'so_phieu1', 'so_phieu2', 'ngay_phieu1', 'ngay_phieu2', 'so_ct1', 'so_ct2', 'so_hd1', 'so_hd2', 'ngay_hd1', 'ngay_hd2', 'ngay_ct1', 'ngay_ct2', 'status', 'user_id0', 'ma_dvcs', 's6', 'ext_key'], [result[1].Value, '', '', null, null, '', '', '', '', null, null, null, null, '*', 0, '', 0, extKey]);
        gd.set_memvars(a);
        gd._gridPageSize = 1;
        gd.goToPage(-1);
      }
      else {
        var cell = g._getItem(1, 1);
        var hyperlinkFormatString = "~/AppHandler/Voucher.ashx Query: {Name: 'PT0', Value: '" + result[1].Value + "'}"";
        g._navigate(cell, hyperlinkFormatString);
      }
      break;
    case 'Delete':
      if (result[0].Value != '') {
         $message.show(result[0].Value, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      } else {
        var msg = (g._language == 'v') ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.';
        $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      }
      break;
    default:
      break;
  }
}
function setValue$Array(a, f, v) {for(var i = 0; i < f.length; i++) Array.add(a, {Name: f[i], OldValue: null, NewValue: v[i] , Modified: true, Items: []});}
function request$ARAllocation(g, c) {g.request(g, c, c, [['s', 'Infinite', g._$k], ['ngay_tu', 'DateTime', g._dFrom], ['ngay_den', 'DateTime', g._dTo]]);}
function request$ARDrillDown(g, c) {g.request(g, c, c, [['s', 'String', g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec'))]]);}
function request$ARCreate(g, c) {
  if (g._activeRow <= 0) return;
  var gd = g._grid, a = [], key = g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec'));
  var c = String.fromCharCode(253), extKey = key + c + g._allocationType;
  setValue$Array(a, ['ext_key'], [extKey]);
  gd.set_memvars(a);
  gd.executeCommand({commandName:'New',commandArgument:'0'});
}
function createGrid(element, g, id, offsetHeight) {
    return $create(FastBusiness.AjaxControlExtender.ReportExtender, {
      memvars: [],
      externalKey: [],
      offsetHeight: offsetHeight,
      baseUrl: g._baseUrl,
      controller: 'RDTran',
      cookie: g._cookie,
      denySessionStorage: g._denySessionStorage,
      id: id,
      parentGrid: g,
      initPageSize: 0,
      language: g._language,
      offsetTime: g._offsetTime,
      readOnly: true,
      serviceLookup: g._serviceLookup,
      serviceMethod: g._serviceMethod,
      servicePath: g._servicePath
    }, null, null, element);
}
